快速入门NodeMCU，开发板的Hello World。 NodeMCU远程点亮灯泡目标：远程点亮一个灯泡 硬件：ModeMCU 基础知识ESP8266和NodeMCU： ESP8266是一块芯片，NodeMCU是以ESP8266芯片为核心的开发板 ESP8266的三种工作模式： STA(Station)：ESP8266主动去连接WIFI AP(Wireless Access Point)：ESP8266创建WIFI STA+AP：上面两个共存 API： WiFiServer，Serial.begin()，pinMode()，Serial.print() 板载小灯： GPIO2引脚与板载小灯相联 在esp8266的库文件中hardware/esp8266/3.0.2/variants/nodemcu/pins_arduino.h中定义了各种引脚 基本思路ESP8266以STA模式工作，连接到WIFI后，自己内部启动一个TCP server，这个TCP server其实是写一个小型的HTTP服务器，客户端通过浏览器就可以访问到。 代码： 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105#include &lt;ESP8266WiFi.h&gt;//此处设置您的wifi接入信息#ifndef STASSID#define STASSID &quot;WiFi&quot; // wifi名称#define STAPSK &quot;password&quot; //要连接的wifi密码#endifconst char *ssid = STASSID;const char *password = STAPSK;//创建TCP server对象,并将端口指定为80WiFiServer server(80);void setup(){ //打开串口 Serial.begin(115200); //初始化板载LED pinMode(LED_BUILTIN, OUTPUT); digitalWrite(LED_BUILTIN, 0); //连接WiFi Serial.println(); Serial.println(); Serial.print(F(&quot;Connecting to &quot;)); Serial.println(ssid); WiFi.mode(WIFI_STA); WiFi.begin(ssid, password); while (WiFi.status() != WL_CONNECTED) { delay(500); Serial.print(F(&quot;.&quot;)); } Serial.println(); Serial.println(F(&quot;WiFi connected&quot;)); //启动TCP server服务器 server.begin(); Serial.println(F(&quot;Server started&quot;)); //打印IP地址 Serial.println(WiFi.localIP());}void loop(){ //检查客户端是否已连接 WiFiClient client = server.available(); if (!client) { return; } Serial.println(F(&quot;new client&quot;)); client.setTimeout(5000); //默认为 1000 //读取客户端发起的TCP请求 String req = client.readStringUntil(''); Serial.println(F(&quot;request: &quot;)); Serial.println(req); //解析请求里是否含有以下指定内容 int val; //检查发起的请求内容是否包含&quot;/gpio/0&quot; if (req.indexOf(F(&quot;/gpio/0&quot;)) != -1) { val = 0; //检查发起的请求内容是否包含&quot;/gpio/1&quot; } else if (req.indexOf(F(&quot;/gpio/1&quot;)) != -1) { val = 1; } else { Serial.println(F(&quot;invalid request&quot;)); val = digitalRead(LED_BUILTIN); } //根据要求设置板载LED状态 digitalWrite(LED_BUILTIN, val); //读取剩余的内容,用于清除缓存 while (client.available()) { client.read(); } //将响应体发送到客户端 注:若要使用中文则必须在其中添加&lt;meta charset=\&quot;utf-8\&quot;&gt;声明编码 client.print(F(&quot;HTTP/1.1 200 OK
Content-Type: text/html

&lt;!DOCTYPE HTML&gt;
&lt;html&gt;
&lt;meta charset=\&quot;utf-8\&quot;&gt;NodeMCU板载LED灯的状态 : &quot;)); client.print((val) ? F(&quot;关&quot;) : F(&quot;开&quot;)); client.print(F(&quot;&lt;br&gt;&lt;br&gt; &lt;a href='http://&quot;)); client.print(WiFi.localIP()); client.print(F(&quot;/gpio/1'&gt; 点击关灯 &lt;/a&gt; , 或 &lt;a href='http://&quot;)); client.print(WiFi.localIP()); client.print(F(&quot;/gpio/0'&gt; 点击开灯 &lt;/a&gt; &lt;/html&gt;&quot;)); //通过浏览器点击按钮之后,TCP连接将会被重置,并且浏览器会发起新的TCP请求到我们的8266服务器,从而去控制LED灯 Serial.println(F(&quot;Disconnecting from client&quot;));} 参考资料：太极创客
